# TypeScript Generics

Generics let you write functions, classes, and types that work with any type while preserving type information. Instead of using `any`, generics capture the specific type at each call site.

## Generic Functions

```typescript
// Without generics — loses type information
function firstAny(arr: any[]): any {
  return arr[0];
}
const x = firstAny([1, 2, 3]); // any — lost the number type

// With generics — preserves type information
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}
const y = first([1, 2, 3]);      // number | undefined — inferred
const z = first<string>(["a"]);  // string | undefined — explicit

// Multiple type parameters
function pair<A, B>(a: A, b: B): [A, B] {
  return [a, b];
}
const p = pair("hello", 42); // [string, number]

// Generic arrow functions
const identity = <T>(x: T): T => x;

// In .tsx files, use trailing comma to disambiguate from JSX
const identity2 = <T,>(x: T): T => x;
```

## Type Parameter Constraints

Use `extends` to restrict what types a generic parameter can accept.

```typescript
// T must have a 'length' property
function longest<T extends { length: number }>(a: T, b: T): T {
  return a.length >= b.length ? a : b;
}

longest("hello", "world");   // OK — strings have length
longest([1, 2], [1, 2, 3]);  // OK — arrays have length
// longest(10, 20);           // Error: number has no 'length'

// Constrain to keys of an object
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

const user = { name: "Alice", age: 30 };
getProperty(user, "name"); // string
getProperty(user, "age");  // number
// getProperty(user, "email"); // Error: not a key of user
```

## Default Type Parameters

Provide defaults when a type parameter is not explicitly specified.

```typescript
interface ApiResponse<T = unknown> {
  data: T;
  status: number;
  headers: Record<string, string>;
}

const response1: ApiResponse = { data: "anything", status: 200, headers: {} };
const response2: ApiResponse<User> = { data: user, status: 200, headers: {} };

// Defaults with constraints
type Container<T extends object = Record<string, unknown>> = {
  value: T;
  meta: string;
};
```

## Generic Interfaces

```typescript
interface Repository<T> {
  findById(id: string): Promise<T | null>;
  findAll(): Promise<T[]>;
  create(item: Omit<T, "id">): Promise<T>;
  update(id: string, item: Partial<T>): Promise<T>;
  delete(id: string): Promise<void>;
}

interface User {
  id: string;
  name: string;
  email: string;
}

class UserRepository implements Repository<User> {
  async findById(id: string): Promise<User | null> { /* ... */ return null; }
  async findAll(): Promise<User[]> { return []; }
  async create(item: Omit<User, "id">): Promise<User> { return { id: "1", ...item }; }
  async update(id: string, item: Partial<User>): Promise<User> { return { id, name: "", email: "", ...item }; }
  async delete(id: string): Promise<void> { /* ... */ }
}
```

## Generic Classes

```typescript
class Stack<T> {
  private items: T[] = [];

  push(item: T): void {
    this.items.push(item);
  }

  pop(): T | undefined {
    return this.items.pop();
  }

  peek(): T | undefined {
    return this.items[this.items.length - 1];
  }

  get size(): number {
    return this.items.length;
  }
}

const numStack = new Stack<number>();
numStack.push(1);
numStack.push(2);
const top = numStack.pop(); // number | undefined
```

## The `infer` Keyword

`infer` declares a type variable inside a conditional type, extracting parts of a type.

```typescript
// Extract return type
type Return<T> = T extends (...args: any[]) => infer R ? R : never;
type A = Return<() => string>;   // string
type B = Return<(x: number) => boolean>; // boolean

// Extract element type from array
type Flatten<T> = T extends (infer E)[] ? E : T;
type C = Flatten<number[]>;    // number
type D = Flatten<string>;      // string (not an array, returns as-is)

// Extract promise value
type UnwrapPromise<T> = T extends Promise<infer U> ? UnwrapPromise<U> : T;
type E = UnwrapPromise<Promise<Promise<number>>>;  // number

// Extract function parameters
type FirstParam<T> = T extends (first: infer F, ...rest: any[]) => any ? F : never;
type F = FirstParam<(name: string, age: number) => void>; // string

// Infer in template literal types
type ExtractId<T> = T extends `${infer _Prefix}-${infer Id}` ? Id : never;
type G = ExtractId<"user-123">;  // "123"
```

## Conditional Types with Generics

```typescript
// Distribute over unions
type ToArray<T> = T extends unknown ? T[] : never;
type H = ToArray<string | number>; // string[] | number[]

// Filter a union
type FilterStrings<T> = T extends string ? T : never;
type I = FilterStrings<string | number | boolean>; // string

// Recursive conditional types
type DeepReadonly<T> = T extends object
  ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;

type ReadonlyUser = DeepReadonly<{
  name: string;
  address: { street: string; city: string };
}>;
// { readonly name: string; readonly address: { readonly street: string; readonly city: string } }

// NonNullable implementation
type MyNonNullable<T> = T extends null | undefined ? never : T;
```

## `const` Type Parameters (5.0+)

Preserve literal types in generic inference.

```typescript
// Without const — widens to string[]
function withoutConst<T extends readonly string[]>(arr: T): T {
  return arr;
}
const a1 = withoutConst(["a", "b"]); // string[]

// With const — preserves literal types
function withConst<const T extends readonly string[]>(arr: T): T {
  return arr;
}
const a2 = withConst(["a", "b"]); // readonly ["a", "b"]
```

## Variance Annotations (4.7+)

Explicitly mark type parameter variance for correctness and performance.

```typescript
// 'out' — covariant (producer)
interface Producer<out T> {
  get(): T;
}

// 'in' — contravariant (consumer)
interface Consumer<in T> {
  accept(value: T): void;
}

// 'in out' — invariant (both)
interface ReadWrite<in out T> {
  get(): T;
  set(value: T): void;
}
```

Variance annotations are checked by the compiler: if you mark `out T` but use `T` in an input position, TypeScript reports an error.

## Common Generic Patterns

### Type-Safe Event Emitter

```typescript
type EventMap = {
  connect: { host: string; port: number };
  message: { text: string; from: string };
  disconnect: { reason: string };
};

class TypedEmitter<Events extends Record<string, unknown>> {
  private listeners = new Map<string, Set<Function>>();

  on<K extends keyof Events>(event: K, handler: (data: Events[K]) => void): void {
    const set = this.listeners.get(event as string) ?? new Set();
    set.add(handler);
    this.listeners.set(event as string, set);
  }

  emit<K extends keyof Events>(event: K, data: Events[K]): void {
    this.listeners.get(event as string)?.forEach(fn => fn(data));
  }
}

const emitter = new TypedEmitter<EventMap>();
emitter.on("connect", (data) => {
  console.log(data.host); // typed: { host: string; port: number }
});
```

### Builder Pattern

```typescript
class QueryBuilder<T extends object> {
  private conditions: string[] = [];

  where<K extends keyof T>(key: K, value: T[K]): this {
    this.conditions.push(`${String(key)} = ${JSON.stringify(value)}`);
    return this;
  }

  build(): string {
    return this.conditions.join(" AND ");
  }
}

interface Product {
  name: string;
  price: number;
  category: string;
}

const query = new QueryBuilder<Product>()
  .where("category", "electronics")  // OK
  .where("price", 99.99)             // OK
  // .where("price", "cheap")        // Error: string not assignable to number
  .build();
```

### Branded / Opaque Types

```typescript
type Brand<T, B extends string> = T & { __brand: B };

type UserId = Brand<string, "UserId">;
type OrderId = Brand<string, "OrderId">;

function getUser(id: UserId): void { /* ... */ }
function getOrder(id: OrderId): void { /* ... */ }

const userId = "user-123" as UserId;
const orderId = "order-456" as OrderId;

getUser(userId);   // OK
// getUser(orderId); // Error: OrderId not assignable to UserId
```

## Generic Pitfalls

### 1. Over-constraining

```typescript
// Bad — T is constrained but never used beyond the constraint
function bad<T extends string>(x: T): string {
  return x.toUpperCase();
}
// Better — just use string directly
function good(x: string): string {
  return x.toUpperCase();
}
```

### 2. Unnecessary generics

```typescript
// Bad — T is only used once, provides no benefit
function bad2<T>(x: T): void {
  console.log(x);
}
// Better
function good2(x: unknown): void {
  console.log(x);
}
```

### 3. Not constraining enough

```typescript
// Bad — T could be anything, .name might not exist
// function getName<T>(obj: T): string {
//   return obj.name; // Error
// }

// Good — constrain to types with a name property
function getName<T extends { name: string }>(obj: T): string {
  return obj.name;
}
```

**Rule of thumb**: Use generics when the type parameter appears in at least two positions (input and output, or two inputs that must match). If it appears only once, you probably don't need a generic.
